/// <summary>
///  The <c>ETG_InventFairValuePostController</c> class is the controller class for working with
/// service operations.
/// </summary>
class ETG_InventFairValuePostController extends SysOperationServiceController
{
    ETG_InventFairValueLineTable       inventFairValueLineTable ;
    ETG_InventFairValueHeaderTable     InventFairValueHeaderTable;
    Amount                             Total;
}

Method.Source:
public ETG_InventFairValueLineTable parminventFairValueLineTable(ETG_InventFairValueLineTable _inventFairValueLineTable = inventFairValueLineTable)
{
    inventFairValueLineTable    = _inventFairValueLineTable;
    return inventFairValueLineTable;
}

public ETG_InventFairValueHeaderTable parmInventFairValueHeaderTable(ETG_InventFairValueHeaderTable _InventFairValueHeaderTable = InventFairValueHeaderTable)
{
    InventFairValueHeaderTable  = _InventFairValueHeaderTable;
    return InventFairValueHeaderTable;
}

public static ETG_InventFairValuePostController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
 {
   ETG_InventFairValuePostController controller;
   controller    = new ETG_InventFairValuePostController();
   controller.parmExecutionMode(_executionMode);
   return controller;
 }

public static void main(Args _args)
{
    ETG_InventFairValuePostController controller  =  ETG_InventFairValuePostController::construct();

    controller.parmArgs(_args);
    controller.parmInventFairValueHeaderTable(_args.caller().parmInventFairValueHeaderTable());
    controller.startOperation();

}

public SysOperationStartResult startOperation()
{
    SysOperationStartResult ret;
    this.getDataContractObject().parmInventFairValueHeaderTable(this.parmInventFairValueHeaderTable());  

    while select DifferenceValue from inventFairValueLineTable
        where (InventFairValueHeaderTable.FairValuationSerialNumber ==  inventFairValueLineTable.FairValuationSerialNumber)
   {
       Total      = Total + inventFairValueLineTable.DifferenceValue;

   }

    Total      = round(Total , 0.01);
    this.getDataContractObject().parmAmount(Total) ;
    ret  = super();

    return ret;
}
